<script setup lang="ts">
import { Head, router, useForm } from '@inertiajs/vue3';
import Button from 'primevue/button'; import InputText from 'primevue/inputtext'; import InputNumber from 'primevue/inputnumber'; import Textarea from 'primevue/textarea';
type StepIngredient = { id: number; quantity: string | null; unit: string | null; notes: string | null; ingredient: { id: number; name: string } | null };
type RecipeStep = { id: number; sort_order: number; name: string | null; description: string | null; humidity: string | null; temperature: string | null; duration_minutes: number | null; ingredients: StepIngredient[] };
type Recipe = { id: number; name: string; print_name: string | null; tag: string | null; season: string | null; yield_quantity: string | null; yield_unit: string | null; total_minutes: number | null; preparation_minutes: number | null; cooking_minutes: number | null; shelf_life_days: number | null; presentation: string | null; storage_instructions: string | null; notes: string | null; steps: RecipeStep[] };
const props = defineProps<{ recipe: Recipe | null }>();
const form = useForm({ name: props.recipe?.name ?? '', print_name: props.recipe?.print_name ?? '', tag: props.recipe?.tag ?? '', season: props.recipe?.season ?? '', yield_quantity: props.recipe?.yield_quantity ? Number(props.recipe.yield_quantity) : null, yield_unit: props.recipe?.yield_unit ?? '', total_minutes: props.recipe?.total_minutes ?? null, preparation_minutes: props.recipe?.preparation_minutes ?? null, cooking_minutes: props.recipe?.cooking_minutes ?? null, shelf_life_days: props.recipe?.shelf_life_days ?? null, presentation: props.recipe?.presentation ?? '', storage_instructions: props.recipe?.storage_instructions ?? '', notes: props.recipe?.notes ?? '' });
function submit(): void {
 if (props.recipe) {
  form.put('/operativita/recipes/' + props.recipe.id);
 } else {
  form.post('/operativita/recipes');
 }
}
function remove(): void {
 if (props.recipe && window.confirm('Eliminare questa ricetta?')) {
router.delete('/operativita/recipes/' + props.recipe.id);
} 
}
defineOptions({ layout: { breadcrumbs: [{ title: 'Ricette', href: '/operativita/recipes' }, { title: 'Modifica', href: '/operativita/recipes' }] } });
</script>
<template><Head :title="recipe ? 'Modifica ' + recipe.name : 'Nuova ricetta'" /><div class="mx-auto flex w-full max-w-5xl flex-1 flex-col gap-4 p-3 md:p-5"><header class="flex items-end justify-between border-b border-border pb-3"><div><h1 class="font-serif text-2xl text-[#2c4133]">{{ recipe ? 'Modifica ricetta' : 'Nuova ricetta' }}</h1><p class="text-sm text-muted-foreground">{{ recipe?.steps?.length ? recipe.steps.length + ' fasi di preparazione importate.' : 'I passaggi e gli ingredienti potranno essere aggiunti nella scheda ricetta.' }}</p></div><Button v-if="recipe" label="Elimina" severity="danger" text @click="remove" /></header><form class="grid gap-4 rounded-xl border border-border bg-card p-4 shadow-sm" @submit.prevent="submit"><div class="grid gap-4 md:grid-cols-2"><label class="grid gap-1 text-sm font-medium">Nome<InputText v-model="form.name" /><small v-if="form.errors.name" class="text-destructive">{{ form.errors.name }}</small></label><label class="grid gap-1 text-sm font-medium">Nome stampa<InputText v-model="form.print_name" /></label><label class="grid gap-1 text-sm font-medium">Tag<InputText v-model="form.tag" placeholder="es. base, dessert" /></label><label class="grid gap-1 text-sm font-medium">Stagione<InputText v-model="form.season" /></label><label class="grid gap-1 text-sm font-medium">Resa<InputNumber v-model="form.yield_quantity" :min="0" /><InputText v-model="form.yield_unit" placeholder="unità" /></label><label class="grid gap-1 text-sm font-medium">Durata totale (min)<InputNumber v-model="form.total_minutes" :min="0" /></label><label class="grid gap-1 text-sm font-medium">Preparazione (min)<InputNumber v-model="form.preparation_minutes" :min="0" /></label><label class="grid gap-1 text-sm font-medium">Cottura (min)<InputNumber v-model="form.cooking_minutes" :min="0" /></label><label class="grid gap-1 text-sm font-medium">Conservazione (giorni)<InputNumber v-model="form.shelf_life_days" :min="0" /></label></div><label class="grid gap-1 text-sm font-medium">Presentazione<Textarea v-model="form.presentation" rows="3" /></label><label class="grid gap-1 text-sm font-medium">Conservazione<Textarea v-model="form.storage_instructions" rows="3" /></label><label class="grid gap-1 text-sm font-medium">Note<Textarea v-model="form.notes" rows="3" /></label><div class="flex justify-end gap-2"><Button as="a" href="/operativita/recipes" label="Annulla" severity="secondary" outlined /><Button type="submit" :label="recipe ? 'Salva modifiche' : 'Crea ricetta'" :loading="form.processing" /></div></form><section v-if="recipe" class="grid gap-3"><div class="flex items-center justify-between"><h2 class="font-serif text-xl text-[#2c4133]">Fasi e ingredienti</h2><span class="text-sm text-muted-foreground">{{ recipe.steps?.length ?? 0 }} fasi</span></div><div v-if="!recipe.steps?.length" class="rounded-xl border border-border bg-card p-6 text-center text-sm text-muted-foreground">Nessuna fase collegata a questa ricetta.</div><article v-for="(step, index) in recipe.steps" :key="step.id" class="rounded-xl border border-border bg-card p-4 shadow-sm"><header class="flex flex-wrap items-start justify-between gap-2 border-b border-border pb-3"><div><p class="text-xs font-semibold uppercase tracking-wide text-muted-foreground">Fase {{ index + 1 }}<span v-if="step.sort_order"> · {{ step.sort_order }}</span></p><h3 class="text-lg font-semibold text-[#2c4133]">{{ step.name || 'Fase senza nome' }}</h3></div><div class="flex flex-wrap gap-2 text-xs text-muted-foreground"><span v-if="step.duration_minutes">{{ step.duration_minutes }} min</span><span v-if="step.temperature">{{ step.temperature }} °C</span><span v-if="step.humidity">{{ step.humidity }} % umidità</span></div></header><p v-if="step.description" class="whitespace-pre-line py-3 text-sm text-muted-foreground">{{ step.description }}</p><div v-if="step.ingredients?.length" class="border-t border-border pt-3"><h4 class="mb-2 text-xs font-semibold uppercase tracking-wide text-muted-foreground">Ingredienti della fase</h4><div class="grid gap-2 sm:grid-cols-2"><div v-for="item in step.ingredients" :key="item.id" class="flex items-center justify-between gap-3 rounded-lg bg-muted/40 px-3 py-2 text-sm"><span>{{ item.ingredient?.name || 'Ingrediente non trovato' }}</span><span class="shrink-0 font-semibold">{{ item.quantity || '—' }} {{ item.unit || '' }}</span></div></div></div><p v-else class="border-t border-border pt-3 text-sm text-muted-foreground">Nessun ingrediente associato.</p></article></section></div></template>
